    static int Main(string[] args)
    {
        try { return MainImpl(args); }
        catch (Exception ex)
        {
            Console.Error.WriteLine("Launcher error: " + ex.GetType().FullName);
            Console.Error.WriteLine(ex.Message);
            Console.Error.WriteLine(ex.StackTrace);
            if (Environment.UserInteractive)
            {
                Console.WriteLine();
                Console.Write("Process failed. Press Enter to close...");
                Console.ReadLine();
            }
            return 1;
        }
    }

    static int MainImpl(string[] args)
    {
        string work = Path.Combine(Path.GetTempPath(), "VpnDeployCombined-" + Guid.NewGuid().ToString("N"));
        Directory.CreateDirectory(work);
        string androidBin = Path.Combine(work, "android-bin");
        Directory.CreateDirectory(androidBin);

        string mainScript = Path.Combine(work, "VpnDeployCombined.ps1");
        string androidScript = Path.Combine(work, "VpnDeployAndroid.ps1");
        string checkScript = Path.Combine(work, "wireguard_check_start.sh");
        string wg = Path.Combine(androidBin, "wg-arm64");
        string plink = Path.Combine(work, "plink.exe");
        string pscp = Path.Combine(work, "pscp.exe");
        WriteFile(mainScript, MainScriptB64);
        WriteFile(androidScript, AndroidScriptB64);
        WriteFile(checkScript, CheckScriptB64);
        WriteFile(wg, WgB64);
        WriteFile(plink, PlinkB64);
        WriteFile(pscp, PscpB64);

        var command = new StringBuilder();
        command.Append("-NoProfile -ExecutionPolicy Bypass -File ");
        command.Append(Quote(mainScript));
        foreach (string arg in args)
        {
            command.Append(' ');
            command.Append(Quote(arg));
        }

        var psi = new ProcessStartInfo
        {
            FileName = "powershell.exe",
            Arguments = command.ToString(),
            UseShellExecute = false,
            WorkingDirectory = work
        };

        int exitCode;
        using (var process = Process.Start(psi))
        {
            process.WaitForExit();
            exitCode = process.ExitCode;
        }

        try { Directory.Delete(work, true); } catch { }

        if (Environment.UserInteractive)
        {
            Console.WriteLine();
            Console.Write(exitCode == 0 ? "Process finished. Press Enter to close..." : "Process failed. Press Enter to close...");
            Console.ReadLine();
        }
        return exitCode;
    }

    static void WriteFile(string path, string[] chunks)
    {
        File.WriteAllBytes(path, Convert.FromBase64String(string.Concat(chunks)));
    }

    static string Quote(string value)
    {
        if (value == null) return "\"\"";
        return "\"" + value.Replace("\\", "\\\\").Replace("\"", "\\\"") + "\"";
    }
}